exercises.solution_code:
def take(n, iterable):
    # Yield at most the first `n` items of any iterable, then stop. Because we
    # pull items one at a time and stop early, this works even on an infinite
    # source: we never iterate past what we yield.
    if n <= 0:
        return
    count = 0
    for item in iterable:
        yield item
        count += 1
        if count >= n:
            return

